  ('elementary-d0d1b9a2-moex-00119', 'elementary-d0d1b9a2', 'elementary-d0d1b9a2-moex-114-426aa0fd', 'sub-elementary-d0d1b9a2-03', NULL, 'single_choice', '甲公司於X1年1月1日發行12%，10年期$100,000公司債，每年6月30日與12月31日付息，發行當 時有效利率為10%，發行價格為$112,463。甲公司X1年攤銷之溢價金額為何？（答案四捨五入至元）', '["$12,000", "$1,246", "$773", "$754"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:44+00:00", "source_pdf_sha1": "d892cb86a6ac", "answer_pdf_sha1": "1de06b7d4c79", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "511", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "會計學大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "會計"}'::jsonb, NULL),
